<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    user-select: none;
  }
  h1 {
    font-size: 2rem;
    margin-bottom: 12px;
    color: #00ff88;
    text-shadow: 0 0 20px rgba(0,255,136,0.3);
    letter-spacing: 4px;
  }
  #score {
    font-size: 1.4rem;
    margin-bottom: 16px;
    color: #ffd700;
    text-shadow: 0 0 10px rgba(255,215,0,0.3);
  }
  #snake {
    border: 2px solid #00ff88;
    border-radius: 4px;
    box-shadow: 0 0 30px rgba(0,255,136,0.15), inset 0 0 30px rgba(0,0,0,0.3);
    display: block;
  }
  .controls {
    margin-top: 18px;
    display: flex;
    gap: 12px;
  }
  .controls button {
    padding: 10px 28px;
    font-size: 1rem;
    font-weight: 600;
    border: 2px solid #00ff88;
    border-radius: 6px;
    background: transparent;
    color: #00ff88;
    cursor: pointer;
    transition: all 0.2s;
    letter-spacing: 1px;
  }
  .controls button:hover {
    background: #00ff88;
    color: #1a1a2e;
    box-shadow: 0 0 15px rgba(0,255,136,0.4);
  }
  .controls button:active {
    transform: scale(0.96);
  }
  #status {
    margin-top: 14px;
    font-size: 0.95rem;
    color: #888;
    min-height: 1.4em;
  }
</style>
</head>
<body>

<h1>SNAKE</h1>
<div id="score">Score: 0</div>
<canvas id="snake" width="400" height="400"></canvas>
<div class="controls">
  <button id="start">Start</button>
  <button id="pause">Pause</button>
  <button id="reset">Reset</button>
</div>
<div id="status">Press Start or use arrow keys to play</div>

<script>
(function() {
  const CELL = 20;
  const W = 20;
  const H = 20;
  const TICK_MS = 120;

  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');
  const statusEl = document.getElementById('status');

  let snake = [];
  let food = null;
  let dir = 'right';
  let dirQueue = [];
  let alive = false;
  let score = 0;
  let intervalId = null;
  let gameStarted = false;

  const OPPOSITE = { up: 'down', down: 'up', left: 'right', right: 'left' };
  const DIR_VEC = { up: [0,-1], down: [0,1], left: [-1,0], right: [1,0] };

  function isOpposite(a, b) {
    return OPPOSITE[a] === b;
  }

  function randomFreeCell() {
    const occupied = new Set(snake.map(s => s.x + ',' + s.y));
    const free = [];
    for (let x = 0; x < W; x++) {
      for (let y = 0; y < H; y++) {
        if (!occupied.has(x + ',' + y)) free.push([x, y]);
      }
    }
    if (free.length === 0) return [0, 0];
    return free[Math.floor(Math.random() * free.length)];
  }

  function draw() {
    // Background
    ctx.fillStyle = '#0d0d1a';
    ctx.fillRect(0, 0, W * CELL, H * CELL);

    // Grid lines (subtle)
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= W; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL, 0);
      ctx.lineTo(x * CELL, H * CELL);
      ctx.stroke();
    }
    for (let y = 0; y <= H; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL);
      ctx.lineTo(W * CELL, y * CELL);
      ctx.stroke();
    }

    // Food
    if (food) {
      const fx = food[0] * CELL + CELL / 2;
      const fy = food[1] * CELL + CELL / 2;
      // Glow
      const grad = ctx.createRadialGradient(fx, fy, 2, fx, fy, CELL);
      grad.addColorStop(0, 'rgba(255,60,60,0.9)');
      grad.addColorStop(1, 'rgba(255,60,60,0)');
      ctx.fillStyle = grad;
      ctx.fillRect(fx - CELL, fy - CELL, CELL * 2, CELL * 2);
      // Apple
      ctx.fillStyle = '#ff3c3c';
      ctx.beginPath();
      ctx.arc(fx, fy, CELL / 2 - 2, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = '#ff6666';
      ctx.beginPath();
      ctx.arc(fx - 2, fy - 2, CELL / 5, 0, Math.PI * 2);
      ctx.fill();
    }

    // Snake
    if (snake.length > 0) {
      for (let i = snake.length - 1; i >= 0; i--) {
        const s = snake[i];
        const px = s.x * CELL;
        const py = s.y * CELL;
        const pad = 1;

        if (i === 0) {
          // Head
          ctx.fillStyle = '#00ff88';
          ctx.shadowColor = '#00ff88';
          ctx.shadowBlur = 10;
          roundRect(ctx, px + pad, py + pad, CELL - pad * 2, CELL - pad * 2, 5);
          ctx.fill();
          ctx.shadowBlur = 0;

          // Eyes
          const dv = DIR_VEC[dir];
          const ex1 = px + CELL / 2 + dv[0] * 3 - dv[1] * 4;
          const ey1 = py + CELL / 2 + dv[1] * 3 - dv[0] * 4;
          const ex2 = px + CELL / 2 + dv[0] * 3 + dv[1] * 4;
          const ey2 = py + CELL / 2 + dv[1] * 3 + dv[0] * 4;
          ctx.fillStyle = '#0d0d1a';
          ctx.beginPath();
          ctx.arc(ex1, ey1, 2.5, 0, Math.PI * 2);
          ctx.fill();
          ctx.beginPath();
          ctx.arc(ex2, ey2, 2.5, 0, Math.PI * 2);
          ctx.fill();
        } else {
          // Body - gradient from green to teal
          const t = i / snake.length;
          const r = Math.round(0 + t * 0);
          const g = Math.round(255 - t * 100);
          const b = Math.round(136 - t * 80);
          ctx.fillStyle = `rgb(${r},${g},${b})`;
          roundRect(ctx, px + pad + 1, py + pad + 1, CELL - (pad + 1) * 2, CELL - (pad + 1) * 2, 4);
          ctx.fill();
        }
      }
    }

    // Game over overlay
    if (!alive && gameStarted) {
      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.fillRect(0, 0, W * CELL, H * CELL);
      ctx.fillStyle = '#ff4444';
      ctx.font = 'bold 32px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('GAME OVER', W * CELL / 2, H * CELL / 2 - 15);
      ctx.fillStyle = '#ccc';
      ctx.font = '18px sans-serif';
      ctx.fillText('Score: ' + score, W * CELL / 2, H * CELL / 2 + 20);
    }
  }

  function roundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function updateScore() {
    scoreEl.textContent = 'Score: ' + score;
  }

  function doTick() {
    if (!alive) return;

    // Process direction queue
    if (dirQueue.length > 0) {
      const nextDir = dirQueue.shift();
      if (!isOpposite(nextDir, dir)) {
        dir = nextDir;
      }
      // If it was opposite, we just ignore it (snake keeps heading)
    }

    const head = snake[0];
    const dv = DIR_VEC[dir];
    const newHead = { x: head.x + dv[0], y: head.y + dv[1] };

    // Wall collision
    if (newHead.x < 0 || newHead.x >= W || newHead.y < 0 || newHead.y >= H) {
      alive = false;
      stopInterval();
      draw();
      statusEl.textContent = 'Game Over! Hit a wall.';
      return;
    }

    // Self collision
    for (let i = 0; i < snake.length; i++) {
      if (snake[i].x === newHead.x && snake[i].y === newHead.y) {
        alive = false;
        stopInterval();
        draw();
        statusEl.textContent = 'Game Over! Hit yourself.';
        return;
      }
    }

    snake.unshift(newHead);

    // Food collision
    if (food && newHead.x === food[0] && newHead.y === food[1]) {
      score++;
      updateScore();
      food = randomFreeCell();
    } else {
      snake.pop();
    }

    draw();
  }

  function startInterval() {
    if (intervalId) return;
    intervalId = setInterval(doTick, TICK_MS);
  }

  function stopInterval() {
    if (intervalId) {
      clearInterval(intervalId);
      intervalId = null;
    }
  }

  function doReset() {
    stopInterval();
    gameStarted = false;
    alive = false;
    score = 0;
    dir = 'right';
    dirQueue = [];
    updateScore();

    // Snake starts length 3, moving right
    snake = [
      { x: 5, y: 10 },
      { x: 4, y: 10 },
      { x: 3, y: 10 }
    ];

    food = randomFreeCell();
    draw();
    statusEl.textContent = 'Press Start or use arrow keys to play';
  }

  function doStart() {
    if (alive) return;
    if (!gameStarted) {
      // First start: initialize
      if (snake.length === 0) doReset();
      alive = true;
      gameStarted = true;
      statusEl.textContent = 'Playing...';
    } else if (!alive) {
      // Restart after game over
      doReset();
      alive = true;
      gameStarted = true;
      statusEl.textContent = 'Playing...';
    }
    startInterval();
  }

  function doPause() {
    if (!alive) return;
    if (intervalId) {
      stopInterval();
      statusEl.textContent = 'Paused';
    } else {
      startInterval();
      statusEl.textContent = 'Playing...';
    }
  }

  // Keyboard controls
  document.addEventListener('keydown', function(e) {
    const keyMap = {
      ArrowUp: 'up', ArrowDown: 'down',
      ArrowLeft: 'left', ArrowRight: 'right',
      w: 'up', s: 'down', a: 'left', d: 'right'
    };
    const kd = keyMap[e.key];
    if (kd) {
      e.preventDefault();
      if (!gameStarted) {
        doStart();
      }
      setDir(kd);
    }
  });

  // Button handlers
  document.getElementById('start').addEventListener('click', doStart);
  document.getElementById('pause').addEventListener('click', doPause);
  document.getElementById('reset').addEventListener('click', doReset);

  // Public API
  window.game = {
    get w() { return W; },
    get h() { return H; },

    reset: function() {
      doReset();
    },

    tick: function() {
      doTick();
    },

    setDir: function(d) {
      if (d !== 'up' && d !== 'down' && d !== 'left' && d !== 'right') return;
      // If queue is empty, check against current dir
      // If queue has items, check against last queued dir
      const effectiveDir = dirQueue.length > 0 ? dirQueue[dirQueue.length - 1] : dir;
      if (!isOpposite(d, effectiveDir)) {
        dirQueue.push(d);
      }
      // If opposite, ignore (180° reversal)
    },

    setFood: function(x, y) {
      food = [x, y];
      draw();
    },

    snake: function() {
      return snake.map(function(s) { return [s.x, s.y]; });
    },

    food: function() {
      return food ? [food[0], food[1]] : null;
    },

    alive: function() {
      return alive;
    },

    score: function() {
      return score;
    }
  };

  // Initial draw
  doReset();
})();
</script>
</body>
</html>
